svg.script:
(function () {
  var PANEL = "panel87_simple_gates_worktable";
  function collect() {
    var svg = document.querySelector("svg") || document.documentElement;
    var vb = svg.viewBox && svg.viewBox.baseVal;
    var VW = vb && vb.width ? vb.width : 1448;
    var VH = vb && vb.height ? vb.height : 1086;
    var rootM = null;
    try { rootM = svg.getScreenCTM(); } catch (e) { rootM = null; }
    function box(rect) {
      var bb;
      try { bb = rect.getBBox(); } catch (e) { return null; }
      var m = null;
      try { if (rootM) { m = rootM.inverse().multiply(rect.getScreenCTM()); } } catch (e) { m = null; }
      if (!m) { return { x: bb.x, y: bb.y, w: bb.width, h: bb.height }; }
      function map(x, y) { return { x: m.a * x + m.c * y + m.e, y: m.b * x + m.d * y + m.f }; }
      var p = [map(bb.x, bb.y), map(bb.x + bb.width, bb.y), map(bb.x, bb.y + bb.height), map(bb.x + bb.width, bb.y + bb.height)];
      var xs = [p[0].x, p[1].x, p[2].x, p[3].x], ys = [p[0].y, p[1].y, p[2].y, p[3].y];
      var minX = Math.min.apply(null, xs), maxX = Math.max.apply(null, xs);
      var minY = Math.min.apply(null, ys), maxY = Math.max.apply(null, ys);
      return { x: minX, y: minY, w: maxX - minX, h: maxY - minY };
    }
    function pct(rect) {
      var b = box(rect);
      if (!b || !(b.w > 0) || !(b.h > 0)) return null;
      return { x: b.x / VW * 100, y: b.y / VH * 100, w: b.w / VW * 100, h: b.h / VH * 100 };
    }
    var rects = document.querySelectorAll("[data-hotspot]");
    var out = { panel: PANEL, objects: [], table: null, actions: {} };
    for (var i = 0; i < rects.length; i++) {
      var r = rects[i], kind = r.getAttribute("data-hotspot"), g = pct(r);
      if (!g) continue;
      if (kind === "object") {
        out.objects.push({ id: r.getAttribute("data-id") || r.id || "", label: r.getAttribute("data-label") || "", url: r.getAttribute("data-url") || "", x: g.x, y: g.y, w: g.w, h: g.h });
      } else if (kind === "table") {
        out.table = { label: r.getAttribute("data-label") || "\u05e9\u05d5\u05dc\u05d7\u05df \u05e2\u05d1\u05d5\u05d3\u05d4", x: g.x, y: g.y, w: g.w, h: g.h };
      } else if (kind === "action") {
        var a = r.getAttribute("data-action");
        if (a) { out.actions[a] = { x: g.x, y: g.y, w: g.w, h: g.h }; }
      }
    }
    return out;
  }
  function send() {
    try {
      if (window.parent && window.parent !== window) {
        window.parent.postMessage({ __warehouseHotspots: true, payload: collect() }, "*");
      }
    } catch (e) {}
  }
  function boot() { send(); setTimeout(send, 120); setTimeout(send, 500); }
  if (document.readyState === "loading") { window.addEventListener("DOMContentLoaded", boot); }
  else { boot(); }
  window.addEventListener("load", send);
})();
